let favorites = []

document.addEventListener("DOMContentLoaded", () => {
    
})


function loadFavorites() {
    const stored = localStorage.getItem("favorites");
    stored ? favorites = JSON.parse(stored) : favorites = [];
}

function favoriteSystem(comic, buttonText, wrapperElement) {
    if (!buttonText || !wrapperElement) return;
    comic.favorite = !comic.favorite;

    if (comic.favorite) {
        const sentFavorite = structuredClone(comic) // structucedClone() copy objects, array, etc
        favorites.push(sentFavorite);

        buttonText.textContent = "✔"
        buttonText.classList.add("favorite-button-active")
        wrapperElement.classList.add("favorite-button-wrapper-active")


    } else {
        favorites = favorites.filter(f => f.id !== comic.id);

        buttonText.textContent = "Favorite"
        buttonText.classList.remove("favorite-button-active")
        wrapperElement.classList.remove("favorite-button-wrapper-active")
    }


    localStorage.setItem("favorites", JSON.stringify(favorites));
}

function syncButtons(container) {
    const favoriteBtnWrapper = container.querySelectorAll(".favorite-button-wrapper");
    const favoriteBtn = container.querySelectorAll(".favorite-button");

    favoriteBtn.forEach(btn => {
        const comicId = Number(btn.dataset.id);
        const comic = comics.find(c => c.id === comicId);

        if (!comic) return;

        comic.favorite = favorites.some(fav => fav.id === comicId);

        const wrapper = btn.closest(".favorite-button-wrapper")

        if (comic.favorite) {
            btn.textContent = "✔"
            btn.classList.add("favorite-button-active")
            if (wrapper) {wrapper.classList.add("favorite-button-wrapper-active")}
        } else {
            btn.textContent = "Favorite"
            btn.classList.remove("favorite-button-active")
            if (wrapper) {wrapper.classList.remove("favorite-button-wrapper-active")}
        }

   })

}

function attachEventListeners(container) {
    const favoriteBtn = container.querySelectorAll(".favorite-button");

    favoriteBtn.forEach(btn => {
        btn.addEventListener("click", () => {
            const comicId = Number(btn.dataset.id);
            const comic = comics.find(c => c.id === comicId);

            if (!comic) return;

            const wrapper = btn.closest(".favorite-button-wrapper");

            favoriteSystem(comic, btn, wrapper);
            console.log(favorites)
        });
    });
}

